proof_block:
let (sp1, ack1) = r1;
    let (sp2, ack2) = r2;

    // Definitional unfolding tautologies that bring per-packet triggers
    // (outbound_packet_is_valid(&sp_i@[i]) and sp_i@[i].src@) into z3's
    // local fact set for both runs, so the disjoint per-run quantifiers
    // from the two ensures-conjuncts can be instantiated at matching indices.
    assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(sp1@)
           =~= sp1@.map_values(|cp: CPacket| cp@).to_set());
    assert(abstractify_seq_of_cpackets_to_set_of_sht_packets(sp2@)
           =~= sp2@.map_values(|cp: CPacket| cp@).to_set());

    assert(outbound_packet_seq_is_valid(sp1@) <==>
           (forall |i: int| 0 <= i < sp1@.len() ==> #[trigger] outbound_packet_is_valid(&sp1@[i])));
    assert(outbound_packet_seq_is_valid(sp2@) <==>
           (forall |i: int| 0 <= i < sp2@.len() ==> #[trigger] outbound_packet_is_valid(&sp2@[i])));

    assert(outbound_packet_seq_has_correct_srcs(sp1@, pre_self_.constants.me@) <==>
           (forall |i: int| 0 <= i < sp1@.len() ==> #[trigger] sp1@[i].src@ == pre_self_.constants.me@));
    assert(outbound_packet_seq_has_correct_srcs(sp2@, pre_self_.constants.me@) <==>
           (forall |i: int| 0 <= i < sp2@.len() ==> #[trigger] sp2@[i].src@ == pre_self_.constants.me@));
